import{_ as t,o as r,c as d,ai as s}from"./chunks/framework.Bke2s2V8.js";const m=JSON.parse('{"title":"Alphabet et prononciation","description":"","frontmatter":{},"headers":[],"relativePath":"module-1-fondations/alphabet-prononciation.md","filePath":"module-1-fondations/alphabet-prononciation.md","lastUpdated":1773298982000}'),a={name:"module-1-fondations/alphabet-prononciation.md"};function o(i,e,n,l,g,v){return r(),d("div",null,[...e[0]||(e[0]=[s('<h1 id="alphabet-et-prononciation" tabindex="-1">Alphabet et prononciation <a class="header-anchor" href="#alphabet-et-prononciation" aria-label="Permalink to “Alphabet et prononciation”">​</a></h1><p><strong>Prérequis :</strong> aucun.</p><p><strong>Objectif :</strong> lire et prononcer l&#39;allemand correctement dès le départ. Une bonne prononciation facilite la mémorisation et évite de prendre de mauvaises habitudes.</p><p>L&#39;allemand s&#39;écrit comme il se prononce - bien plus régulièrement que le français. Une fois les règles connues, tu peux lire n&#39;importe quel mot à voix haute sans l&#39;avoir jamais vu.</p><h2 id="l-alphabet" tabindex="-1">L&#39;alphabet <a class="header-anchor" href="#l-alphabet" aria-label="Permalink to “L&#39;alphabet”">​</a></h2><p>L&#39;alphabet allemand contient les 26 lettres latines classiques, plus 4 caractères spécifiques : <strong>ä</strong>, <strong>ö</strong>, <strong>ü</strong> et <strong>ß</strong>.</p><div class="mt-6 grid grid-cols-4 gap-2 text-center"><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">A a</div><div class="text-sm text-gray-500 mt-1">ah</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">B b</div><div class="text-sm text-gray-500 mt-1">bé</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">C c</div><div class="text-sm text-gray-500 mt-1">tsé</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">D d</div><div class="text-sm text-gray-500 mt-1">dé</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">E e</div><div class="text-sm text-gray-500 mt-1">é</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">F f</div><div class="text-sm text-gray-500 mt-1">ef</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">G g</div><div class="text-sm text-gray-500 mt-1">gué</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">H h</div><div class="text-sm text-gray-500 mt-1">ha</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">I i</div><div class="text-sm text-gray-500 mt-1">i</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">J j</div><div class="text-sm text-gray-500 mt-1">yot</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">K k</div><div class="text-sm text-gray-500 mt-1">ka</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">L l</div><div class="text-sm text-gray-500 mt-1">el</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">M m</div><div class="text-sm text-gray-500 mt-1">em</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">N n</div><div class="text-sm text-gray-500 mt-1">en</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">O o</div><div class="text-sm text-gray-500 mt-1">o</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">P p</div><div class="text-sm text-gray-500 mt-1">pé</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">Q q</div><div class="text-sm text-gray-500 mt-1">kou</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">R r</div><div class="text-sm text-gray-500 mt-1">er</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">S s</div><div class="text-sm text-gray-500 mt-1">es</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">T t</div><div class="text-sm text-gray-500 mt-1">té</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">U u</div><div class="text-sm text-gray-500 mt-1">ou</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">V v</div><div class="text-sm text-gray-500 mt-1">fau</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">W w</div><div class="text-sm text-gray-500 mt-1">vé</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">X x</div><div class="text-sm text-gray-500 mt-1">iks</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">Y y</div><div class="text-sm text-gray-500 mt-1">ypsilon</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100"><div class="text-xl font-bold text-gray-900">Z z</div><div class="text-sm text-gray-500 mt-1">tsett</div></div></div><h3 id="les-4-caracteres-specifiques" tabindex="-1">Les 4 caractères spécifiques <a class="header-anchor" href="#les-4-caracteres-specifiques" aria-label="Permalink to “Les 4 caractères spécifiques”">​</a></h3><div class="mt-4 grid grid-cols-2 gap-3"><div class="p-4 rounded-lg border border-green-200 bg-green-50"><div class="text-2xl font-bold text-green-800">Ä ä</div><div class="text-sm text-gray-600 mt-2">Se prononce comme le <strong>é</strong> français. <br> Ex : <em>Mädchen</em> (fille)</div></div><div class="p-4 rounded-lg border border-green-200 bg-green-50"><div class="text-2xl font-bold text-green-800">Ö ö</div><div class="text-sm text-gray-600 mt-2">Se prononce comme le <strong>eu</strong> français. <br> Ex : <em>schön</em> (beau)</div></div><div class="p-4 rounded-lg border border-green-200 bg-green-50"><div class="text-2xl font-bold text-green-800">Ü ü</div><div class="text-sm text-gray-600 mt-2">Se prononce comme le <strong>u</strong> français. <br> Ex : <em>über</em> (au-dessus)</div></div><div class="p-4 rounded-lg border border-green-200 bg-green-50"><div class="text-2xl font-bold text-green-800">ß</div><div class="text-sm text-gray-600 mt-2">Double S long. Uniquement en minuscule. <br> Ex : <em>Straße</em> (rue)</div></div></div><div class="info custom-block"><p class="custom-block-title">Le ß sur un clavier français</p><p>Si tu n&#39;as pas de clavier allemand, tu peux remplacer ß par <strong>ss</strong> - c&#39;est accepté partout. Alternativement : sur Windows <code>Alt + 0223</code>, sur Mac <code>Option + s</code>.</p></div><h2 id="regles-de-prononciation" tabindex="-1">Règles de prononciation <a class="header-anchor" href="#regles-de-prononciation" aria-label="Permalink to “Règles de prononciation”">​</a></h2><h3 id="les-combinaisons-a-connaitre" tabindex="-1">Les combinaisons à connaître <a class="header-anchor" href="#les-combinaisons-a-connaitre" aria-label="Permalink to “Les combinaisons à connaître”">​</a></h3><p>Ce sont les sons qui piègent les francophones au départ.</p><div class="mt-4 grid gap-3"><div class="flex items-start gap-4 p-4 rounded-lg border border-gray-200"><div class="text-xl font-bold text-green-600 w-16 shrink-0">ei</div><div><div class="font-medium text-gray-900">Se prononce <strong>aï</strong></div><div class="text-sm text-gray-500 mt-1">Ex : <em>nein</em> (non), <em>drei</em> (trois), <em>Eis</em> (glace)</div></div></div><div class="flex items-start gap-4 p-4 rounded-lg border border-gray-200"><div class="text-xl font-bold text-green-600 w-16 shrink-0">ie</div><div><div class="font-medium text-gray-900">Se prononce <strong>i long</strong></div><div class="text-sm text-gray-500 mt-1">Ex : <em>Liebe</em> (amour), <em>viel</em> (beaucoup), <em>sieben</em> (sept)</div></div></div><div class="warning custom-block"><p class="custom-block-title">ei et ie - ne pas confondre</p><p><em>ei</em> = <strong>aï</strong> / <em>ie</em> = <strong>i long</strong>. C&#39;est l&#39;inverse de ce qu&#39;on attendrait. <em>wein</em> (vin) se prononce &quot;vaïn&quot;, <em>Wien</em> (Vienne) se prononce &quot;viin&quot;. Ce piège fait trébucher beaucoup de débutants.</p></div><div class="flex items-start gap-4 p-4 rounded-lg border border-gray-200"><div class="text-xl font-bold text-green-600 w-16 shrink-0">eu / äu</div><div><div class="font-medium text-gray-900">Se prononce <strong>oï</strong></div><div class="text-sm text-gray-500 mt-1">Ex : <em>neu</em> (nouveau), <em>Häuser</em> (maisons), <em>heute</em> (aujourd&#39;hui)</div></div></div><div class="flex items-start gap-4 p-4 rounded-lg border border-gray-200"><div class="text-xl font-bold text-green-600 w-16 shrink-0">sch</div><div><div class="font-medium text-gray-900">Se prononce <strong>ch</strong> comme dans &quot;chat&quot;</div><div class="text-sm text-gray-500 mt-1">Ex : <em>Schule</em> (école), <em>schön</em> (beau), <em>Fisch</em> (poisson)</div></div></div><div class="flex items-start gap-4 p-4 rounded-lg border border-gray-200"><div class="text-xl font-bold text-green-600 w-16 shrink-0">ch</div><div><div class="font-medium text-gray-900">Deux sons selon la voyelle qui précède</div><div class="text-sm text-gray-500 mt-1">Après a, o, u : son guttural du fond de la gorge - <em>Buch</em> (livre), <em>auch</em> (aussi)<br>Après e, i, ä, ö, ü : son doux, proche de &quot;hy&quot; - <em>ich</em> (je), <em>Milch</em> (lait)</div></div></div><div class="flex items-start gap-4 p-4 rounded-lg border border-gray-200"><div class="text-xl font-bold text-green-600 w-16 shrink-0">sp / st</div><div><div class="font-medium text-gray-900">En début de mot : <strong>chp</strong> / <strong>cht</strong></div><div class="text-sm text-gray-500 mt-1">Ex : <em>sprechen</em> (parler) = &quot;chprechen&quot;, <em>Student</em> = &quot;chtudent&quot;<br>Au milieu d&#39;un mot, on prononce normalement : <em>Fenster</em> (fenêtre)</div></div></div><div class="flex items-start gap-4 p-4 rounded-lg border border-gray-200"><div class="text-xl font-bold text-green-600 w-16 shrink-0">z</div><div><div class="font-medium text-gray-900">Se prononce <strong>ts</strong></div><div class="text-sm text-gray-500 mt-1">Ex : <em>zehn</em> (dix) = &quot;tsehn&quot;, <em>Zeit</em> (temps) = &quot;tsaït&quot;</div></div></div><div class="flex items-start gap-4 p-4 rounded-lg border border-gray-200"><div class="text-xl font-bold text-green-600 w-16 shrink-0">w</div><div><div class="font-medium text-gray-900">Se prononce <strong>v</strong></div><div class="text-sm text-gray-500 mt-1">Ex : <em>Wasser</em> (eau) = &quot;vasser&quot;, <em>wo</em> (ou) = &quot;vo&quot;</div></div></div><div class="flex items-start gap-4 p-4 rounded-lg border border-gray-200"><div class="text-xl font-bold text-green-600 w-16 shrink-0">v</div><div><div class="font-medium text-gray-900">Se prononce <strong>f</strong> dans les mots allemands</div><div class="text-sm text-gray-500 mt-1">Ex : <em>Vater</em> (père) = &quot;fater&quot;, <em>viel</em> (beaucoup) = &quot;fiel&quot;<br>Exception : mots d&#39;origine étrangère comme <em>Visum</em>, où le v se prononce v</div></div></div></div><div class="warning custom-block"><p class="custom-block-title">W et V - l&#39;inversion</p><p>En allemand, <strong>w</strong> se prononce comme notre &quot;v&quot;, et <strong>v</strong> se prononce comme notre &quot;f&quot;. C&#39;est systématiquement l&#39;inverse du français. <em>Wein</em> = &quot;vaïn&quot;, <em>Vater</em> = &quot;fater&quot;.</p></div><h3 id="le-h-muet" tabindex="-1">Le h muet <a class="header-anchor" href="#le-h-muet" aria-label="Permalink to “Le h muet”">​</a></h3><p>Le <strong>h</strong> ne se prononce pas quand il suit une voyelle - il allonge simplement le son.</p><p>Ex : <em>fahren</em> (conduire) = &quot;faaren&quot;, <em>Uhr</em> (heure) = &quot;our&quot;</p><p>En début de mot, le h est aspiré : <em>Haus</em> (maison) = &quot;haous&quot;.</p><h3 id="le-r-allemand" tabindex="-1">Le r allemand <a class="header-anchor" href="#le-r-allemand" aria-label="Permalink to “Le r allemand”">​</a></h3><p>Le <strong>r</strong> allemand se prononce au fond de la gorge, comme un léger gargarisme. Il n&#39;est pas roulé comme en espagnol. En fin de mot ou de syllabe, il devient presque muet et se confond avec un &quot;a&quot; court.</p><p>Ex : <em>Bruder</em> (frère) = &quot;broudeur&quot;, <em>Tür</em> (porte) = &quot;tüa&quot;</p><div class="tip custom-block"><p class="custom-block-title">Apprendre le r allemand</p><p>Essaie de faire le son du &quot;r&quot; français du fond de la gorge en exagérant. Avec le temps il devient naturel. Ne cherche pas la perfection dès le début - un r un peu approximatif reste compréhensible.</p></div>',23)])])}const x=t(a,[["render",o]]);export{m as __pageData,x as default};
